1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	function cellWillLive(isAlive: boolean, liveNeighbors: number): boolean {
10	  return liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
11	}
12	
13	export function nextGeneration(liveCells: Cell[]): Cell[] {
14	  const liveKeys = new Set(liveCells.map(toKey));
15	  const neighborCounts = new Map<string, number>();
16	
17	  for (const [x, y] of liveCells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const neighborKey = toKey([x + dx, y + dy]);
20	      neighborCounts.set(neighborKey, (neighborCounts.get(neighborKey) ?? 0) + 1);
21	    }
22	  }
23	
24	  const nextLive: Cell[] = [];
25	  for (const [neighborKey, count] of neighborCounts) {
26	    if (cellWillLive(liveKeys.has(neighborKey), count)) {
27	      nextLive.push(fromKey(neighborKey));
28	    }
29	  }
30	  return nextLive;
31	}
32	
33	function toKey([x, y]: Cell): string {
34	  return `${x},${y}`;
35	}
36	
37	function fromKey(k: string): Cell {
38	  const [x, y] = k.split(",");
39	  return [Number(x), Number(y)];
40	}
