export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(toKey));
  const neighborCounts = countLiveNeighbors(liveCells);

  const nextLive: Cell[] = [];
  for (const [candidateKey, count] of neighborCounts) {
    if (cellWillLive(liveKeys.has(candidateKey), count)) {
      nextLive.push(fromKey(candidateKey));
    }
  }
  return nextLive;
}

function countLiveNeighbors(liveCells: Cell[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighborKey = toKey([x + dx, y + dy]);
      counts.set(neighborKey, (counts.get(neighborKey) ?? 0) + 1);
    }
  }
  return counts;
}
